package main

import "fmt"

func main() {
    // A map with string Keys (names) and int Values (ages)
    ages := map[string]int{
        "Alice": 25,
        "Bob":   30,
    }

    // Adding a new entry
    ages["Charlie"] = 35

    // Looking up Bob's age directly by his name!
    fmt.Println("Bob is", ages["Bob"])
}
